mapper.select:
SELECT report_date AS date, IFNULL(SUM(turnover), 0) AS turnover, IFNULL(SUM(order_count), 0) AS order_count, IFNULL(SUM(valid_order_count), 0) AS valid_order_count, IFNULL(SUM(new_users), 0) AS new_users FROM (SELECT DATE(order_time) AS report_date, SUM(CASE WHEN `status` = 5 THEN amount ELSE 0 END) AS turnover, COUNT(*) AS order_count, SUM(CASE WHEN `status` = 5 THEN 1 ELSE 0 END) AS valid_order_count, 0 AS new_users FROM orders WHERE order_time >= #{begin} AND order_time < #{end} GROUP BY DATE(order_time)
UNION ALL
SELECT DATE(create_time) AS report_date, 0 AS turnover, 0 AS order_count, 0 AS valid_order_count, COUNT(*) AS new_users FROM `user` WHERE create_time >= #{begin} AND create_time < #{end} GROUP BY DATE(create_time)) t GROUP BY report_date ORDER BY report_date;
